from flask import Flask, request, jsonify
import secrets
import sqlite3
import smtplib
from email.mime.text import MIMEText
from datetime import datetime, timedelta

app = Flask(__name__)

# Database setup
def init_db():
    conn = sqlite3.connect('users.db')
    c = conn.cursor()
    c.execute('''CREATE TABLE IF NOT EXISTS users
                 (id INTEGER PRIMARY KEY, email TEXT UNIQUE, password TEXT)''')
    c.execute('''CREATE TABLE IF NOT EXISTS password_resets
                 (id INTEGER PRIMARY KEY, email TEXT, token TEXT, created_at TIMESTAMP)''')
    conn.commit()
    conn.close()

# Generate reset token
def generate_token():
    return secrets.token_urlsafe(32)

# Send reset email
def send_reset_email(email, token):
    # Simplified email sending - replace with actual SMTP setup
    reset_link = f"http://yoursite.com/reset?token={token}"
    print(f"Reset link for {email}: {reset_link}")
    # In production, use smtplib to send actual email

# Password reset endpoint
@app.route('/reset-request', methods=['POST'])
def reset_request():
    data = request.get_json()
    email = data.get('email')
    
    if not email:
        return jsonify({'error': 'Email is required'}), 400
    
    try:
        conn = sqlite3.connect('users.db')
        c = conn.cursor()
        c.execute("SELECT * FROM users WHERE email = ?", (email,))
        user = c.fetchone()
        
        if not user:
            return jsonify({'error': 'User not found'}), 404
        
        token = generate_token()
        c.execute("INSERT INTO password_resets (email, token, created_at) VALUES (?, ?, ?)",
                  (email, token, datetime.now()))
        conn.commit()
        conn.close()
        
        send_reset_email(email, token)
        
        return jsonify({'message': 'Reset link sent to your email'})
    
    except Exception as e:
        return jsonify({'error': 'Internal server error'}), 500

# Reset password endpoint
@app.route('/reset', methods=['POST'])
def reset_password():
    data = request.get_json()
    token = data.get('token')
    new_password = data.get('password')
    
    if not token or not new_password:
        return jsonify({'error': 'Token and password are required'}), 400
    
    try:
        conn = sqlite3.connect('users.db')
        c = conn.cursor()
        
        # Check if token exists and is not expired (1 hour)
        c.execute("SELECT email FROM password_resets WHERE token = ? AND created_at > ?", 
                 (token, datetime.now() - timedelta(hours=1)))
        reset_request = c.fetchone()
        
        if not reset_request:
            return jsonify({'error': 'Invalid or expired token'}), 400
        
        email = reset_request[0]
        
        # Update user password (in production, hash the password)
        c.execute("UPDATE users SET password = ? WHERE email = ?", (new_password, email))
        c.execute("DELETE FROM password_resets WHERE token = ?", (token,))
        conn.commit()
        conn.close()
        
        return jsonify({'message': 'Password reset successfully'})
    
    except Exception as e:
        return jsonify({'error': 'Internal server error'}), 500

